const content = 'Clean this hourly air quality data for Madrid. Aggregate to daily averages. Return ONLY a JSON array, one object per day with fields: fetch_date (YYYY-MM-DD), pm25_avg, pm10_avg, no2_avg, o3_avg, pm25_exceeds_who (boolean, threshold 15), no2_exceeds_who (boolean, threshold 25), o3_exceeds_who (boolean, threshold 100), aqi_status (GOOD or WARNING). Return ONLY JSON array, no markdown. Data: ' + JSON.stringify(data);
