const raw = $input.first().json;
const content = raw.choices?.[0]?.message?.content || '[]';
let records = [];
try {
  records = JSON.parse(content.replace(/```json|```/g,'').trim());
} catch(e) {
  const hourly = $('Fetch Air Quality').first().json.hourly;
  const times = hourly.time||[];
  const byDate = {};
  times.forEach((ts,i)=>{
    const date=ts.split('T')[0];
    if(!byDate[date]) byDate[date]={pm25:[],pm10:[],no2:[],o3:[]};
    if(hourly.pm2_5?.[i]!=null) byDate[date].pm25.push(hourly.pm2_5[i]);
    if(hourly.pm10?.[i]!=null) byDate[date].pm10.push(hourly.pm10[i]);
    if(hourly.nitrogen_dioxide?.[i]!=null) byDate[date].no2.push(hourly.nitrogen_dioxide[i]);
    if(hourly.ozone?.[i]!=null) byDate[date].o3.push(hourly.ozone[i]);
  });
  const avg=arr=>arr.length?Math.round(arr.reduce((a,b)=>a+b,0)/arr.length*100)/100:null;
  return Object.entries(byDate).map(([date,v])=>{
    const p=avg(v.pm25),n=avg(v.no2),o=avg(v.o3);
    return {json:{fetch_date:date,pm25_avg:p,pm10_avg:avg(v.pm10),no2_avg:n,o3_avg:o,
      pm25_exceeds_who:p>15,no2_exceeds_who:n>25,o3_exceeds_who:o>100,
      aqi_status:(p>15||n>25||o>100)?'WARNING':'GOOD',
      ingestion_ts:new Date().toISOString()}};
  });
}
if(!Array.isArray(records)) records=[records];
return records.map(r=>({json:{
  fetch_date:r.fetch_date,
  pm25_avg:parseFloat(r.pm25_avg)||null,
  pm10_avg:parseFloat(r.pm10_avg)||null,
  no2_avg:parseFloat(r.no2_avg)||null,
  o3_avg:parseFloat(r.o3_avg)||null,
  pm25_exceeds_who:r.pm25_exceeds_who===true||r.pm25_exceeds_who==='true',
  no2_exceeds_who:r.no2_exceeds_who===true||r.no2_exceeds_who==='true',
  o3_exceeds_who:r.o3_exceeds_who===true||r.o3_exceeds_who==='true',
  aqi_status:r.aqi_status||'GOOD',
  ingestion_ts:new Date().toISOString()
}}));

const todayDate = new Date().toISOString().split('T')[0];
const weatherRows = $('Parse Weather Clean').all().map(i=>i.json);
const marineRows = $('Parse Marine Clean').all().map(i=>i.json);
const aqiRows = $('Parse AQI Clean').all().map(i=>i.json);

// Get dates that already have a health score computed
let existingDates = [];
try {
  existingDates = $('Check Existing Health Scores').all().map(i=>i.json.score_date);
} catch(e) {
  existingDates = [];
}

// Only process weather rows for dates NOT already in health_score table
const newWeatherRows = weatherRows.filter(r => !existingDates.includes(r.fetch_date));

if (newWeatherRows.length === 0) {
  return [{json:{skip: true, message: 'No new dates to process — all dates already have health scores'}}];
}

return newWeatherRows.map((today, idx) => {
  const allIdx = weatherRows.findIndex(r=>r.fetch_date===today.fetch_date);
  const yesterday = weatherRows[allIdx-1]||{};
  const date = today.fetch_date || todayDate;
  const mar = marineRows.find(r=>r.fetch_date===date)||{};
  const todayAQI = aqiRows.find(r=>r.fetch_date===date)||{};

  const breaches=[todayAQI.pm25_exceeds_who,todayAQI.no2_exceeds_who,todayAQI.o3_exceeds_who].filter(Boolean).length;
  const t=parseFloat(today.temp_max)||25;
  const uv=parseFloat(today.uv_index_max)||3;
  const h=parseFloat(today.humidity_max)||40;
  const tS=t<30?25:t<33?20:t<37?10:0;
  const aS=breaches===0?25:breaches===1?15:5;
  const uS=uv<3?25:uv<6?20:uv<8?10:uv<11?5:0;
  const hS=h<40?25:h<60?20:h<80?10:5;
  const total=tS+aS+uS+hS;
  const tempChange=today.temp_max&&yesterday.temp_max
    ?Math.round((today.temp_max-yesterday.temp_max)*10)/10:null;

  return {json:{
    score_date:date,
    total_score:total,
    label:total>=75?'Safe':total>=50?'Caution':total>=25?'High Risk':'Extreme Risk',
    temp_score:tS,aqi_score:aS,uv_score:uS,humidity_score:hS,
    temp_max:t,uv_index:uv,humidity:h,aqi_breaches:breaches,
    pm25_avg:todayAQI.pm25_avg||null,
    no2_avg:todayAQI.no2_avg||null,
    sea_temp:parseFloat(mar.sea_temp_max)||null,
    temp_change_vs_yesterday:tempChange,
    trend_vs_yesterday:tempChange>2?'getting hotter':tempChange<-2?'cooling down':'stable',
    created_at:new Date().toISOString()
  }};
});

const existingDates = $('Check Weather Exists').all().map(i => i.json.fetch_date);
const newRecords = $input.all().map(i => i.json);
const filtered = newRecords.filter(r => !existingDates.includes(r.fetch_date));
if (filtered.length === 0) {
  return [{json: {skipped: true, message: 'All dates already exist'}}];
}
return filtered.map(r => ({json: r}));

