const existingDates = $('Check AQI Exists').all().map(i => i.json.fetch_date);
const newRecords = $input.all().map(i => i.json);
const filtered = newRecords.filter(r => !existingDates.includes(r.fetch_date));
if (filtered.length === 0) {
  return [{json: {skipped: true, message: 'All dates already exist'}}];
}
return filtered.map(r => ({json: r}));

const weatherRows = $('Parse Weather Clean').all().map(i=>i.json);
const aqiRows = $('Parse AQI Clean').all().map(i=>i.json);
const anomalies = [];
const now = new Date().toISOString();

const zscore = (arr,val) => {
  const mean = arr.reduce((a,b)=>a+b,0)/arr.length;
  const std = Math.sqrt(arr.map(x=>(x-mean)**2).reduce((a,b)=>a+b,0)/arr.length);
  return std===0?0:(val-mean)/std;
};

const temps = weatherRows.map(r=>r.temp_max).filter(v=>v!=null);
if(temps.length>3){
  const last = temps[temps.length-1];
  const z = zscore(temps.slice(0,-1),last);
  if(Math.abs(z)>=2.5) anomalies.push({
    detected_at:now,source:'weather_daily',column_name:'temp_max',
    value:last,mean:Math.round(temps.slice(0,-1).reduce((a,b)=>a+b,0)/temps.slice(0,-1).length*10)/10,
    z_score:Math.round(z*100)/100,
    severity:Math.abs(z)>=4?'HIGH':Math.abs(z)>=3?'MEDIUM':'LOW',
    description:`Temperature ${last}°C is ${Math.abs(z).toFixed(1)}σ from baseline`
  });
}

let streak=0;
weatherRows.forEach(r=>{
  if((r.temp_max||0)>=35){streak++;}else{streak=0;}
  if(streak===3) anomalies.push({
    detected_at:now,source:'weather_daily',column_name:'heatwave',
    value:r.temp_max,mean:35,z_score:99,severity:'HIGH',
    description:'Heatwave: 3+ consecutive days >= 35°C'
  });
});

const uvs = weatherRows.map(r=>r.uv_index_max).filter(v=>v!=null);
if(uvs.length>=3){
  const last = uvs[uvs.length-1];
  const z = zscore(uvs.slice(0,-1),last);
  if(Math.abs(z)>=2.5||last>=11) anomalies.push({
    detected_at:now,source:'weather_daily',column_name:'uv_index_max',
    value:last,mean:Math.round(uvs.slice(0,-1).reduce((a,b)=>a+b,0)/uvs.slice(0,-1).length*10)/10,
    z_score:Math.round(z*100)/100,severity:last>=11?'HIGH':'MEDIUM',
    description:`UV Index ${last} — ${last>=11?'EXTREME':'elevated'}`
  });
}

aqiRows.forEach(todayAQI => {
  if(todayAQI.pm25_exceeds_who) anomalies.push({
    detected_at:now,source:'air_quality_daily',column_name:'pm25_avg',
    value:todayAQI.pm25_avg,mean:15,z_score:null,
    severity:todayAQI.pm25_avg>30?'HIGH':'MEDIUM',
    description:`PM2.5 ${todayAQI.pm25_avg} ug/m3 exceeds WHO limit of 15 on ${todayAQI.fetch_date}`
  });
  if(todayAQI.no2_exceeds_who) anomalies.push({
    detected_at:now,source:'air_quality_daily',column_name:'no2_avg',
    value:todayAQI.no2_avg,mean:25,z_score:null,severity:'MEDIUM',
    description:`NO2 ${todayAQI.no2_avg} ug/m3 exceeds WHO limit of 25 on ${todayAQI.fetch_date}`
  });
});

if(anomalies.length===0) return [{json:{
  detected_at:now,source:'system',column_name:'none',
  value:0,mean:0,z_score:0,severity:'NONE',description:'No anomalies detected'
}}];
return anomalies.map(a=>({json:a}));

const weatherRows = $('Parse Weather Clean').all().map(i=>i.json);
const aqiRows = $('Parse AQI Clean').all().map(i=>i.json);

const linReg = (values) => {
  const n = values.length;
  if(n<3) return {predicted:null,r2:0,trend:'insufficient_data',confidence:'low'};
  const meanX=(n-1)/2, meanY=values.reduce((a,b)=>a+b,0)/n;
  const slope=values.map((y,i)=>(i-meanX)*(y-meanY)).reduce((a,b)=>a+b,0)/
    values.map((_,i)=>(i-meanX)**2).reduce((a,b)=>a+b,0);
  const intercept=meanY-slope*meanX;
  const predicted=slope*n+intercept;
  const yHat=values.map((_,i)=>slope*i+intercept);
  const ssTot=values.map(y=>(y-meanY)**2).reduce((a,b)=>a+b,0);
  const ssRes=values.map((y,i)=>(y-yHat[i])**2).reduce((a,b)=>a+b,0);
  const r2=ssTot>0?1-ssRes/ssTot:0;
  return {
    predicted:Math.round(predicted*100)/100,
    r2:Math.round(r2*100)/100,
    trend:slope>0.05?'rising':slope<-0.05?'falling':'stable',
    confidence:r2>0.7?'high':r2>0.4?'medium':'low'
  };
};

const tomorrow = new Date();
tomorrow.setDate(tomorrow.getDate()+1);
const tomorrowDate = tomorrow.toISOString().split('T')[0];
const todayDate = new Date().toISOString().split('T')[0];

const temps = weatherRows.map(r=>r.temp_max).filter(v=>v!=null);
const uvs   = weatherRows.map(r=>r.uv_index_max).filter(v=>v!=null);
const pm25s  = aqiRows.map(r=>r.pm25_avg).filter(v=>v!=null);

const tempPred = linReg(temps);
const uvPred   = linReg(uvs);
const pm25Pred = linReg(pm25s);

const pTemp = tempPred.predicted||25;
const pUV   = uvPred.predicted||3;
const pPM25 = pm25Pred.predicted||10;

const pTempScore = pTemp<30?25:pTemp<33?20:pTemp<37?10:0;
const pUVScore   = pUV<3?25:pUV<6?20:pUV<8?10:pUV<11?5:0;
const pAQIScore  = pPM25<=15?25:pPM25<=30?15:5;
const pTotal     = pTempScore+pUVScore+pAQIScore+18;

return [{json:{
  prediction_date:      todayDate,
  for_date:             tomorrowDate,
  predicted_temp_max:   tempPred.predicted,
  temp_trend:           tempPred.trend,
  temp_confidence:      tempPred.confidence,
  temp_r2:              tempPred.r2,
  predicted_uv_index:   uvPred.predicted,
  uv_trend:             uvPred.trend,
  predicted_pm25:       pm25Pred.predicted,
  pm25_trend:           pm25Pred.trend,
  predicted_health_score: pTotal,
  predicted_label:      pTotal>=75?'Safe':pTotal>=50?'Caution':pTotal>=25?'High Risk':'Extreme Risk',
  tomorrow_weekday:     tomorrow.toLocaleDateString('en-GB',{weekday:'long'}),
  method:               'linear_regression_3day',
  created_at:           new Date().toISOString()
}}];

const scores = $('Compute Health Score').all().map(i=>i.json);
const score = scores[scores.length-1];
const pred = $('Predict Tomorrow').first().json;

const content = `Write a 3-4 sentence daily health briefing for Madrid residents. Start with today's Health Risk Score. Give specific recommendations (hydration, sunscreen, avoid outdoors 12-16h). End with tomorrow's outlook. Under 80 words.

Today:
- Score: ${score.total_score}/100 (${score.label})
- Temp: ${score.temp_max}°C (${score.trend_vs_yesterday})
- UV: ${score.uv_index}
- Humidity: ${score.humidity}%
- AQI breaches: ${score.aqi_breaches}
- Sea temp: ${score.sea_temp}°C

Tomorrow:
- Predicted temp: ${pred.predicted_temp_max}°C (${pred.temp_trend})
- Predicted score: ${pred.predicted_health_score}/100 (${pred.predicted_label})`;

return [{json:{
  model: "llama-3.3-70b-versatile",
  temperature: 0.3,
  max_tokens: 200,
  messages: [{ role: "user", content: content }]
}}];
